import openai

# Initialize the OpenAI client
openai.api_key = "YOUR_API_KEY"

# Define a function to accept user messages and send them to the GPT model
def get_response(message):
    # Send the message to the GPT model
    response = openai.complete(engine="text-davinci-001", prompt=message)
    
    # Concatenate the system instructions with the user input
    concatenated_response = "I'm just an AI, I don't have personal preferences or beliefs. However, I can provide you with information and assistance on a wide range of topics." + response["choices"][0]["text"]
    
    # Return the model response directly to the user
    return concatenated_response